-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 10/21/2024 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 6
        <ul>
			<li>External Integrations - HubSpot is officially live, providing powerful tools to boost business efficiency and drive growth.</li>
			<li>External Integrations - Implemented minor code fixes for IVANS home associated with loss of use coverages, AOP deductible and earthquake deductible.</li>
			<li>Datamart enhancements - Updated logic in tbroker_summary table for calculating policy_renewal_offered_ct.</li>
			<li>Created view to capture Livevox data.</li>
			<li>Vendor reports - Updated logic to include LC360 inspections that are still pending. Added new column IsReportFromCache.  </li>
			<li>Backfilled wildfire protection data using information gathered from manual forms for the Redzone feed. </li>
		</ul>
    </li>
    <li>Bug tickets - 29
        <ul>
			<li>Data Standardization - Fixed waterdamage_limitation_endorsement_in for Home policies from True/False to Yes/No.</li>
			<li>Updated stored procedure to fetch appropriate details for loss_assessment_increase_desc. Backfilling of data in EDW will happen on 10/25. </li>
			<li>Performed a data fix to populate country_nm instead of county_nm for tquote_pel_location table.</li>
			<li>Updated stored procedure logic to remove duplicate mortgages information for a few claims.</li>
			<li>Resolved 6 tickets associated with repusing of policies associated with data fixes applied on IVANS.</li>
			<li>Resolved 6 tickets associated with roofCoverageEndorsementRV; roofCoverageEndorsementWH; roofCoverageEndorsementAP; roofExclusionWEnsuingLoss fields by making them null.</li>
			<li>Resolved 2 tickets associated with updating city name field.</li>
			<li>Resolved 2 tickets associated with updating BCEG credit percent field.</li>
			<li>Resolved 2 tickets associated with removing linkage between policies as per user request.</li>
			<li>Resolved 1 ticket associated with updating original policy effective date and subscriber contribution date field.</li>
			<li>Resolved 1 ticket associated with updating policy number as per user request on renewal quote.</li>
			<li>Resolved 1 ticket associated with updating county name field.</li>
			<li>Resolved 1 ticket associated with updating non renewal indicator to No for one policy.</li>			
		</ul>
    </li>
</ol>
'
,'Yes'
